import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Mettre à jour Fabric","description":"Un guide pour mettre à jour Fabric pas à pas.","frontmatter":{"title":"Mettre à jour Fabric","description":"Un guide pour mettre à jour Fabric pas à pas.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"fr_fr/1.21.4/players/updating-fabric.md","filePath":"versions/1.21.4/translated/fr_fr/players/updating-fabric.md","lastUpdated":1760721669000}`);var c={name:`fr_fr/1.21.4/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Mettre à jour Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Mettre à jour Fabric”">​</a></h1><p>Ce guide explique en détail le processus de mise à jour de Fabric pour le launcher Minecraft.</p><p>Pour les lanceurs tiers, vous devriez consulter leur documentation.</p><p>La mise à jour de Fabric ressemble beaucoup à l&#39;installation de Fabric, donc certains passages seront identiques au guide <a href="./installing-fabric">Installer Fabric</a>.</p><h2 id="pourquoi-mettre-a-jour-fabric-loader-et-voila" tabindex="-1">Pourquoi mettre à jour Fabric Loader ? Et voilà ! <a class="header-anchor" href="#pourquoi-mettre-a-jour-fabric-loader-et-voila" aria-label="Permalink to “Pourquoi mettre à jour Fabric Loader ? Et voilà !”">​</a></h2><p>De nouveaux mods peuvent nécessiter une version plus récente de Fabric Loader pour fonctionner, il est donc important de le garder à jour pour s&#39;assurer de pouvoir utiliser les mods les plus récents.</p><p>Ce guide ne s&#39;applique qu&#39;au launcher Minecraft officiel. Pour les lanceurs tiers, vous devriez consulter leur documentation.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Télécharger l&#39;installateur Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Télécharger l&#39;installateur Fabric”">​</a></h2><p>Vous pouvez télécharger l&#39;installateur Fabric depuis le <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">site de Fabric</a>.</p><p>Si vous utilisez Windows, téléchargez la version <code>.exe</code> (<code>Download For Windows</code>) car elle ne requiert pas d&#39;avoir installé Java sur votre système. Elle utilise à la place le Java fourni avec le launcher officiel.</p><p>Pour macOS et Linux, vous devrez télécharger la version <code>.jar</code>. Parfois, il vous faudra aussi installer Java avant cette étape.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Lancer l&#39;installateur Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Lancer l&#39;installateur Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Fermez Minecraft et le launcher avant de lancer l&#39;installation.</p></div><details class="details custom-block"><summary>Information pour les utilisateurs de MacOS</summary><p>Sur macOS, vous devrez peut-être faire un clic droit sur le fichier <code>.jar</code> dans votre répertoire de téléchargements et cliquer sur <code>Ouvrir</code> pour l&#39;exécuter.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu de l&#39;installateur Fabric sur MacOS" loading="lazy"></p><p>Lorsqu&#39;on vous demande « Êtes-vous sûr de vouloir l&#39;ouvrir ? », cliquez sur « Ouvrir ».</p></details><p>Une fois l&#39;installateur ouvert, vous devriez voir un écran comme celui-ci :</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Installateur Fabric avec &quot;Install&quot; de mis en avant" loading="lazy"></p><p>Pour mettre à jour Fabric, s&#39;assurer que les versions du jeu et de Loader correspondent, puis appuyer sur &#39;Install&#39; (Installer).</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p><strong>Assurez-vous d&#39;avoir décoché &#39;Créer un profil&#39; en exécutant l&#39;installateur, sinon un nouveau profil sera créé, ce qui est indésirable ici.</strong></p></div><h2 id="_3-ouvrir-le-profil-dans-le-launcher-minecraft" tabindex="-1">3. Ouvrir le profil dans le launcher Minecraft <a class="header-anchor" href="#_3-ouvrir-le-profil-dans-le-launcher-minecraft" aria-label="Permalink to “3. Ouvrir le profil dans le launcher Minecraft”">​</a></h2><p>Une fois que l&#39;installateur a terminé, il est désormais possible d&#39;ouvrir le launcher Minecraft et d&#39;aller à l&#39;onglet &#39;Installations&#39;. Il est recommandé d&#39;aller sur votre profil Fabric et d&#39;ouvrir l&#39;écran d&#39;édition.</p><p>Remplacer la version avec la version de Fabric Loader tout juste installée et appuyer sur &#39;Sauvegarder&#39;.</p><p><img src="/assets/players/updating-fabric.png" alt="Mise à jour de la version de Fabric Loader dans le launcher Minecraft" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. Et voilà ! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Et voilà !”">​</a></h2><p>Une fois que ces étapes ont été faites, retourner à l&#39;onglet &#39;Jeu&#39;, sélectionner le profil Fabric depuis le menu déroulant dans le coin inférieur gauche et appuyer sur &#39;Jouer&#39; !</p><p>Si vous rencontrez des problèmes en suivant ce guide, vous pouvez demander de l&#39;aide dans le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a> dans le salon <code>#player-support</code>.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};